/**
 * conflict-register.test.ts — the host-side semantic steering compiler.
 *
 * Mirrors twin-forge conflict-steering.test.ts: the lexicon→vocab-ID bridge must
 * bias the right WORD-INITIAL pieces (skipping bare sub-words), sign the bias by
 * the contact's disposition (avoiding promotes cold/curt, demotes warm/repair),
 * stay inside the signed envelope, and fold cleanly into the orthographic vector.
 */

import { describe, expect, it } from 'vitest';
import { compileSemanticBias, combineBias, type SemanticSteeringGains } from './conflict-register';

const AVOIDING: SemanticSteeringGains = { behavioral: -0.8, aesthetic: -0.6, prosody: 0, harmonic: 0, cap: 6 };
const COMPETING: SemanticSteeringGains = { behavioral: 0.9, aesthetic: -0.5, prosody: 0, harmonic: 0, cap: 6 };

// The HOST tokenizer's decodeToken returns CLEAN decoded words (marker + leading
// space stripped): 'love' not '▁love'. We also include a marker-prefixed and a
// capitalized entry to prove the belt-and-suspenders strip + lowercasing.
const VOCAB = ['fine', 'sorry', 'love', 'Love', 'the', '▁later', 'whatever'];
const at = (vec: number[], piece: string) => vec[VOCAB.indexOf(piece)]!;

describe('compileSemanticBias — signed register bias over the model vocab', () => {
  it('biases decoded register words (case-insensitive, marker-tolerant), neutral tokens 0', () => {
    const v = compileSemanticBias(AVOIDING, VOCAB);
    expect(v.length).toBe(VOCAB.length);
    expect(at(v, 'fine')).not.toBe(0); // clean decoded word (live host shape)
    expect(at(v, 'Love')).not.toBe(0); // capitalized → lowercased → matches
    expect(at(v, '▁later')).not.toBe(0); // surviving marker still handled
    expect(at(v, 'the')).toBe(0); // no register affinity
  });

  it('avoiding: cold promoted (+), warm/repair demoted (−)', () => {
    const v = compileSemanticBias(AVOIDING, VOCAB);
    expect(at(v, 'fine')).toBeGreaterThan(0);
    expect(at(v, '▁later')).toBeGreaterThan(0);
    expect(at(v, 'sorry')).toBeLessThan(0);
    expect(at(v, 'love')).toBeLessThan(0);
    expect(at(v, 'Love')).toBeLessThan(0);
  });

  it('competing: contempt promoted; "fine" sign flips vs avoiding', () => {
    const v = compileSemanticBias(COMPETING, VOCAB);
    expect(at(v, 'whatever')).toBeGreaterThan(0);
    expect(at(v, 'fine')).toBeLessThan(0); // behavioral+ demotes the cold/curt token
  });

  it('stays inside the signed envelope [−cap, +cap]', () => {
    for (const g of [AVOIDING, COMPETING]) {
      for (const b of compileSemanticBias(g, VOCAB)) expect(Math.abs(b)).toBeLessThanOrEqual(g.cap);
    }
  });

  it('identity: cap<=0 ⇒ all zeros (no steering)', () => {
    const v = compileSemanticBias({ ...AVOIDING, cap: 0 }, VOCAB);
    expect(v.every((x) => x === 0)).toBe(true);
  });

  it('combineBias sums orthographic + semantic elementwise', () => {
    const ortho = [1, 0, -2, 0, 0, 0, 0];
    const sem = compileSemanticBias(AVOIDING, VOCAB);
    const combined = combineBias(ortho, sem);
    expect(combined.length).toBe(VOCAB.length);
    expect(combined[0]).toBe(1 + sem[0]!);
    expect(combined[2]).toBe(-2 + sem[2]!);
  });
});
